422	// Read batch
423	#[derive(Debug)]
424	pub struct RBatch {
425	    // The buffer to perform deserializationn from
426	    buffer: ZSlice,
427	    // The batch codec
428	    codec: Zenoh080Batch,
429	    // The batch config
430	    config: BatchConfig,
431	}
432	
433	impl RBatch {
434	    pub fn new<T>(config: BatchConfig, buffer: T) -> Self
435	    where
436	        T: Into<ZSlice>,
437	    {
438	        Self {
439	            buffer: buffer.into(),
440	            codec: Zenoh080Batch::new(),
441	            config,
442	        }
443	    }
444	
445	    pub fn len(&self) -> usize {
446	        self.buffer.len()
447	    }
448	
449	    #[inline(always)]
450	    pub const fn is_empty(&self) -> bool {
451	        self.buffer.is_empty()
452	    }
453	
454	    // Split (length, header, payload) internal buffer slice
455	    #[inline(always)]
456	    fn split<'a>(buffer: &'a [u8], config: &BatchConfig) -> (&'a [u8], &'a [u8], &'a [u8]) {
457	        zsplit!(buffer, config)
458	    }
459	
460	    pub fn initialize<C, T>(&mut self, #[allow(unused_variables)] buff: C) -> ZResult<()>
461	    where
462	        C: Fn() -> T + Copy,
463	        T: AsMut<[u8]> + ZSliceBuffer + 'static,
464	    {
465	        #[allow(unused_variables)]
466	        let (l, h, p) = Self::split(self.buffer.as_slice(), &self.config);
467	
468	        #[cfg(feature = "transport_compression")]
469	        {
470	            if self.config.has_header() {
471	                let b = *h
472	                    .first()
473	                    .ok_or_else(|| zerror!("Batch header not present"))?;
474	                let header = BatchHeader::new(b);
475	
476	                if header.is_compression() {
477	                    let zslice = self.decompress(p, buff)?;
478	                    self.buffer = zslice;
479	                    return Ok(());
480	                }
481	            }
482	        }
483	
484	        self.buffer = self
485	            .buffer
486	            .subslice(l.len() + h.len()..self.buffer.len())
487	            .ok_or_else(|| zerror!("Invalid batch length"))?;
488	
489	        Ok(())
490	    }
491	
492	    #[cfg(feature = "transport_compression")]
493	    fn decompress<T>(&self, payload: &[u8], mut buff: impl FnMut() -> T) -> ZResult<ZSlice>
494	    where
495	        T: AsMut<[u8]> + ZSliceBuffer + 'static,
496	    {
497	        let mut into = (buff)();
498	        let n = lz4_flex::block::decompress_into(payload, into.as_mut())
499	            .map_err(|_| zerror!("Decompression error"))?;
500	        let zslice = ZSlice::new(Arc::new(into), 0, n)
501	            .map_err(|_| zerror!("Invalid decompression buffer length"))?;
502	        Ok(zslice)
503	    }
504	}
