608	    #[test]
609	    fn serialization_batch() {
610	        let config = BatchConfig {
611	            mtu: BatchSize::MAX,
612	            is_streamed: false,
613	            #[cfg(feature = "transport_compression")]
614	            is_compression: false,
615	        };
616	        let mut batch = WBatch::new(config);
617	
618	        let tmsg: TransportMessage = KeepAlive.into();
619	        let mut nmsg = NetworkMessage::from(Push {
620	            wire_expr: WireExpr::empty(),
621	            ext_qos: ext::QoSType::new(Priority::DEFAULT, CongestionControl::Block, false),
622	            ..Push::from(vec![0u8; 8])
623	        });
624	
625	        let mut tmsgs_in = vec![];
626	        let mut nmsgs_in = vec![];
627	
628	        // Serialize assuming there is already a frame
629	        batch.clear();
630	        assert!(batch.encode(nmsg.as_ref()).is_err());
631	        assert_eq!(batch.len(), 0);
632	
633	        let mut frame = FrameHeader {
634	            reliability: Reliability::Reliable,
635	            sn: 0,
636	            ext_qos: frame::ext::QoSType::DEFAULT,
637	        };
638	        nmsg.reliability = frame.reliability;
639	
640	        // Serialize with a frame
641	        batch.encode((nmsg.as_ref(), &frame)).unwrap();
642	        assert_ne!(batch.len(), 0);
643	        nmsgs_in.push(nmsg.clone());
644	
645	        frame.reliability = Reliability::BestEffort;
646	        nmsg.reliability = frame.reliability;
647	        batch.encode((nmsg.as_ref(), &frame)).unwrap();
648	        assert_ne!(batch.len(), 0);
649	        nmsgs_in.push(nmsg.clone());
650	
651	        // Transport
652	        batch.encode(&tmsg).unwrap();
653	        tmsgs_in.push(tmsg.clone());
654	
655	        // Serialize assuming there is already a frame
656	        assert!(batch.encode(nmsg.as_ref()).is_err());
657	        assert_ne!(batch.len(), 0);
658	
659	        // Serialize with a frame
660	        frame.sn = 1;
661	        batch.encode((nmsg.as_ref(), &frame)).unwrap();
662	        assert_ne!(batch.len(), 0);
663	        nmsgs_in.push(nmsg.clone());
664	    }
665	}
