51	
52	// Batches are moved all over the pipeline and are quite big (56B+), so they are boxed to optimize
53	// the moves. They are always reused, so there is no allocation performance penalty.
54	type BoxedWBatch = Box<WBatch>;
55	
56	const RBLEN: usize = QueueSizeConf::MAX;
57	
58	// Inner structure to reuse serialization batches
59	struct StageInRefill {
60	    n_ref_r: Waiter,
61	    s_ref_r: RingBufferReader<BoxedWBatch, RBLEN>,
62	    batch_config: (usize, BatchConfig),
63	    batch_allocs: usize,
64	}
65	
66	#[derive(Debug)]
67	pub(crate) struct TransportClosed;
68	impl fmt::Display for TransportClosed {
69	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
70	        write!(f, "transport closed")
71	    }
72	}
73	impl std::error::Error for TransportClosed {}
74	
75	impl StageInRefill {
76	    fn pull(&mut self) -> Option<BoxedWBatch> {
77	        match self.s_ref_r.pull() {
78	            Some(b) => Some(b),
79	            None if self.batch_allocs < self.batch_config.0 => {
80	                self.batch_allocs += 1;
81	                Some(Box::new(WBatch::new(self.batch_config.1)))
82	            }
83	            None => None,
84	        }
85	    }
86	
87	    fn wait(&self) -> bool {
88	        self.n_ref_r.wait().is_ok()
89	    }
90	
91	    fn wait_deadline(&self, instant: Instant) -> Result<bool, TransportClosed> {
92	        match self.n_ref_r.wait_deadline(instant) {
93	            Ok(()) => Ok(true),
94	            Err(WaitDeadlineError::Deadline) => Ok(false),
95	            Err(WaitDeadlineError::WaitError) => Err(TransportClosed),
96	        }
97	    }
98	}
99	
100	lazy_static::lazy_static! {
101	   static ref LOCAL_EPOCH: Instant = Instant::now();
102	}
103	
104	type AtomicMicroSeconds = AtomicU32;
105	type MicroSeconds = u32;
106	
107	struct AtomicBackoff {
108	    active: CachePadded<AtomicBool>,
109	    bytes: CachePadded<AtomicBatchSize>,
110	    first_write: CachePadded<AtomicMicroSeconds>,
111	}
112	
113	// Inner structure to link the initial stage with the final stage of the pipeline
114	struct StageInOut {
115	    n_out_w: Notifier,
116	    s_out_w: RingBufferWriter<BoxedWBatch, RBLEN>,
117	    atomic_backoff: Arc<AtomicBackoff>,
118	}
119	
120	impl StageInOut {
121	    #[inline]
122	    fn notify(&self, bytes: BatchSize) {
123	        self.atomic_backoff.bytes.store(bytes, Ordering::Relaxed);
124	        if !self.atomic_backoff.active.load(Ordering::Relaxed) {
125	            let _ = self.n_out_w.notify();
126	        }
127	    }
128	
129	    #[inline]
130	    fn move_batch(&mut self, batch: BoxedWBatch) {
131	        let _ = self.s_out_w.push(batch);
132	        self.atomic_backoff.bytes.store(0, Ordering::Relaxed);
133	        let _ = self.n_out_w.notify();
134	    }
135	}
136	
137	struct Current {
138	    batch: Option<BoxedWBatch>,
139	    status: Arc<TransmissionPipelineStatus>,
140	    prioflag: u8,
141	}
142	
143	impl Current {
144	    fn notify_pending(&mut self) {
145	        self.status
146	            .pending
147	            .fetch_or(self.prioflag, Ordering::Relaxed);
148	    }
149	
150	    fn reset_pending(&mut self) {
151	        self.status
152	            .pending
153	            .fetch_and(!self.prioflag, Ordering::Relaxed);
154	    }
155	}
156	
157	// Inner structure containing mutexes for current serialization batch and SNs
158	struct StageInMutex {
159	    current: Arc<Mutex<Current>>,
160	    priority: TransportPriorityTx,
161	}
162	
163	impl StageInMutex {
164	    #[inline]
165	    fn channel(&self, is_reliable: bool) -> MutexGuard<'_, TransportChannelTx> {
166	        if is_reliable {
167	            zlock!(self.priority.reliable)
168	        } else {
169	            zlock!(self.priority.best_effort)
170	        }
171	    }
172	}
173	
174	#[derive(Debug)]
175	struct WaitTime {
176	    wait_time: Duration,
177	    max_wait_time: Option<Duration>,
178	}
179	
180	impl WaitTime {
181	    fn new(wait_time: Duration, max_wait_time: Option<Duration>) -> Self {
182	        Self {
183	            wait_time,
184	            max_wait_time,
185	        }
186	    }
187	
188	    fn advance(&mut self, instant: &mut Instant) {
189	        // grow wait_time exponentially
190	        self.wait_time = self.wait_time.saturating_mul(2);
191	
192	        // check for waiting limits
193	        match &mut self.max_wait_time {
194	            // if we have reached the waiting limit, we do not increase wait instant
195	            Some(max_wait_time) if *max_wait_time == Duration::ZERO => {
196	                tracing::trace!("Backoff increase limit reached")
197	            }
198	            // if the leftover of waiting time is less than next iteration, we select leftover
199	            Some(max_wait_time) if *max_wait_time <= self.wait_time => {
200	                *instant += *max_wait_time;
201	                *max_wait_time = Duration::ZERO;
202	            }
203	            // if the leftover of waiting time is bigger than next iteration, select next iteration
204	            Some(max_wait_time) => {
205	                *instant += self.wait_time;
206	                *max_wait_time -= self.wait_time;
207	            }
208	            // just select next iteration without checking the upper limit
209	            None => {}
210	        }
211	    }
212	
213	    fn wait_time(&self) -> Duration {
214	        self.wait_time
215	    }
216	}
217	
218	#[derive(Clone)]
219	enum DeadlineSetting {
220	    Immediate,
221	    Finite(Instant),
222	}
223	
224	struct LazyDeadline {
225	    deadline: Option<DeadlineSetting>,
226	    wait_time: WaitTime,
227	}
228	
229	impl LazyDeadline {
230	    fn new(wait_time: WaitTime) -> Self {
231	        Self {
232	            deadline: None,
233	            wait_time,
234	        }
235	    }
236	
237	    fn advance(&mut self) {
238	        match self.deadline().to_owned() {
239	            DeadlineSetting::Immediate => {}
240	            DeadlineSetting::Finite(mut instant) => {
241	                self.wait_time.advance(&mut instant);
242	                self.deadline = Some(DeadlineSetting::Finite(instant));
243	            }
244	        }
245	    }
246	
247	    #[inline]
248	    fn deadline(&mut self) -> &mut DeadlineSetting {
249	        self.deadline
250	            .get_or_insert_with(|| match self.wait_time.wait_time() {
251	                Duration::ZERO => DeadlineSetting::Immediate,
252	                nonzero_wait_time => DeadlineSetting::Finite(Instant::now().add(nonzero_wait_time)),
253	            })
254	    }
255	}
256	
257	struct Deadline {
258	    lazy_deadline: LazyDeadline,
259	}
260	
261	impl Deadline {
262	    fn new(wait_time: Duration, max_wait_time: Option<Duration>) -> Self {
263	        Self {
264	            lazy_deadline: LazyDeadline::new(WaitTime::new(wait_time, max_wait_time)),
265	        }
266	    }
267	
268	    #[inline]
269	    fn wait(&mut self, s_ref: &StageInRefill) -> Result<bool, TransportClosed> {
270	        match self.lazy_deadline.deadline() {
271	            DeadlineSetting::Immediate => Ok(false),
272	            DeadlineSetting::Finite(instant) => s_ref.wait_deadline(*instant),
273	        }
274	    }
275	
276	    fn on_next_fragment(&mut self) {
277	        self.lazy_deadline.advance();
278	    }
279	}
280	
281	// This is the initial stage of the pipeline where messages are serliazed on
282	struct StageIn {
283	    s_ref: StageInRefill,
284	    s_out: StageInOut,
285	    mutex: StageInMutex,
286	    fragbuf: ZBuf,
287	    batching: bool,
288	    // used for stop fragment
289	    batch_config: BatchConfig,
290	}
291	
292	impl StageIn {
293	    fn push_network_message(
294	        &mut self,
295	        msg: NetworkMessageRef,
296	        priority: Priority,
297	        deadline: &mut Deadline,
298	    ) -> Result<bool, TransportClosed> {
299	        // Lock the current serialization batch.
300	        let mut c_guard = zlock!(self.mutex.current);
301	        c_guard.notify_pending();
302	
303	        macro_rules! zgetbatch_rets {
304	            ($($restore_sn:stmt)?) => {
305	                loop {
306	                    match c_guard.batch.take() {
307	                        Some(batch) => break batch,
308	                        None => match self.s_ref.pull() {
309	                            Some(mut batch) => {
310	                                batch.clear();
311	                                self.s_out.atomic_backoff.first_write.store(
312	                                    LOCAL_EPOCH.elapsed().as_micros() as MicroSeconds,
313	                                    Ordering::Relaxed,
314	                                );
315	                                break batch;
316	                            }
317	                            None => {
318	                                // Wait for an available batch until deadline
319	                                if !deadline.wait(&self.s_ref)? {
320	                                    // Still no available batch.
321	                                    // Restore the sequence number and drop the message
322	                                    $($restore_sn)?
323	                                    tracing::trace!(
324	                                        "Zenoh message dropped because it's over the deadline {:?}: {:?}",
325	                                        deadline.lazy_deadline.wait_time, msg
326	                                    );
327	                                    return Ok(false);
328	                                }
329	                            }
330	                        },
331	                    }
332	                }
333	            };
334	        }
335	
336	        macro_rules! zretok {
337	            ($batch:expr, $msg:expr) => {{
338	                if !self.batching || $msg.is_express() {
339	                    // Move out existing batch
340	                    self.s_out.move_batch($batch);
341	                    return Ok(true);
342	                } else {
343	                    let bytes = $batch.len();
344	                    c_guard.batch = Some($batch);
345	                    drop(c_guard);
346	                    self.s_out.notify(bytes);
347	                    return Ok(true);
348	                }
349	            }};
350	        }
351	
352	        // Get the current serialization batch.
353	        let mut batch = zgetbatch_rets!();
354	        // Attempt the serialization on the current batch
355	        let e = match batch.encode(msg) {
356	            Ok(_) => zretok!(batch, msg),
357	            Err(e) => e,
358	        };
359	
360	        // Lock the channel. We are the only one that will be writing on it.
361	        let mut tch = self.mutex.channel(msg.is_reliable());
362	
363	        // Retrieve the next SN
364	        let sn = tch.sn.get();
365	
366	        // The Frame
367	        let frame = FrameHeader {
368	            reliability: msg.reliability,
369	            sn,
370	            ext_qos: frame::ext::QoSType::new(priority),
371	        };
372	
373	        if let BatchError::NewFrame = e {
374	            // Attempt a serialization with a new frame
375	            if batch.encode((msg, &frame)).is_ok() {
376	                zretok!(batch, msg);
377	            }
378	        }
379	
380	        if !batch.is_empty() {
381	            // Move out existing batch
382	            self.s_out.move_batch(batch);
383	            batch = zgetbatch_rets!(tch.sn.set(sn).unwrap());
384	        }
385	
386	        // Attempt a second serialization on fully empty batch
387	        if batch.encode((msg, &frame)).is_ok() {
388	            zretok!(batch, msg);
389	        }
390	
391	        // The second serialization attempt has failed. This means that the message is
392	        // too large for the current batch size: we need to fragment.
393	        // Reinsert the current batch for fragmentation.
394	        c_guard.batch = Some(batch);
395	
396	        // Take the expandable buffer and serialize the totality of the message
397	        self.fragbuf.clear();
398	
399	        let mut writer = self.fragbuf.writer();
400	        let codec = Zenoh080::new();
401	        codec.write(&mut writer, msg).unwrap();
402	
403	        // Fragment the whole message
404	        let mut fragment = FragmentHeader {
405	            reliability: frame.reliability,
406	            more: true,
407	            sn,
408	            ext_qos: frame.ext_qos,
409	            ext_first: Some(fragment::ext::First::new()),
410	            ext_drop: None,
411	        };
412	        let mut reader = self.fragbuf.reader();
413	        while reader.can_read() {
414	            // Get the current serialization batch
415	            batch = zgetbatch_rets!({
416	                // If no fragment has been sent, the sequence number is just reset
417	                if fragment.ext_first.is_some() {
418	                    tch.sn.set(sn).unwrap()
419	                // Otherwise, an ephemeral batch is created to send the stop fragment
420	                } else {
421	                    let mut batch = Box::new(WBatch::new_ephemeral(self.batch_config));
422	                    self.fragbuf.clear();
423	                    fragment.ext_drop = Some(fragment::ext::Drop::new());
424	                    let _ = batch.encode((&mut self.fragbuf.reader(), &mut fragment));
425	                    self.s_out.move_batch(batch);
426	                }
427	            });
428	
429	            // Serialize the message fragment
430	            match batch.encode((&mut reader, &mut fragment)) {
431	                Ok(_) => {
432	                    // Update the SN
433	                    fragment.sn = tch.sn.get();
434	                    fragment.ext_first = None;
435	                    // Move the serialization batch into the OUT pipeline
436	                    self.s_out.move_batch(batch);
437	                }
438	                Err(_) => {
439	                    // Restore the sequence number
440	                    tch.sn.set(sn).unwrap();
441	                    // Reinsert the batch
442	                    c_guard.batch = Some(batch);
443	                    tracing::warn!(
444	                        "Zenoh message dropped because it can not be fragmented: {:?}",
445	                        msg
446	                    );
447	                    break;
448	                }
449	            }
450	
451	            // adopt deadline for the next fragment
452	            deadline.on_next_fragment();
453	        }
454	
455	        // Clean the fragbuf
456	        self.fragbuf.clear();
457	
458	        Ok(true)
459	    }
460	
461	    #[inline]
462	    fn push_transport_message(&mut self, msg: TransportMessage) -> bool {
463	        // Lock the current serialization batch.
464	        let mut c_guard = zlock!(self.mutex.current);
465	        c_guard.notify_pending();
466	
467	        macro_rules! zgetbatch_rets {
468	            () => {
469	                loop {
470	                    match c_guard.batch.take() {
471	                        Some(batch) => break batch,
472	                        None => match self.s_ref.pull() {
473	                            Some(mut batch) => {
474	                                batch.clear();
475	                                self.s_out.atomic_backoff.first_write.store(
476	                                    LOCAL_EPOCH.elapsed().as_micros() as MicroSeconds,
477	                                    Ordering::Relaxed,
478	                                );
479	                                break batch;
480	                            }
481	                            None => {
482	                                if !self.s_ref.wait() {
483	                                    return false;
484	                                }
485	                            }
486	                        },
487	                    }
488	                }
489	            };
490	        }
491	
492	        macro_rules! zretok {
493	            ($batch:expr) => {{
494	                if !self.batching {
495	                    // Move out existing batch
496	                    self.s_out.move_batch($batch);
497	                    return true;
498	                } else {
499	                    let bytes = $batch.len();
500	                    c_guard.batch = Some($batch);
501	                    drop(c_guard);
502	                    self.s_out.notify(bytes);
503	                    return true;
504	                }
505	            }};
506	        }
507	
508	        // Get the current serialization batch.
509	        let mut batch = zgetbatch_rets!();
510	        // Attempt the serialization on the current batch
511	        match batch.encode(&msg) {
512	            Ok(_) => zretok!(batch),
513	            Err(_) => {
514	                if !batch.is_empty() {
515	                    self.s_out.move_batch(batch);
516	                    batch = zgetbatch_rets!();
517	                }
518	            }
519	        };
520	
521	        // The first serialization attempt has failed. This means that the current
522	        // batch is full. Therefore, we move the current batch to stage out.
523	        batch.encode(&msg).is_ok()
524	    }
525	}
