869	impl TransmissionPipelineProducer {
870	    #[inline]
871	    pub(crate) fn push_network_message(
872	        &self,
873	        msg: NetworkMessageRef,
874	    ) -> Result<bool, TransportClosed> {
875	        // If the queue is not QoS, it means that we only have one priority with index 0.
876	        let (idx, priority) = if self.stage_in.len() > 1 {
877	            let priority = msg.priority();
878	            (priority as usize, priority)
879	        } else {
880	            (0, Priority::DEFAULT)
881	        };
882	
883	        // If message is droppable, compute a deadline after which the sample could be dropped
884	        let (wait_time, max_wait_time) = if msg.is_droppable() {
885	            // Checked if we are blocked on the priority queue and we drop directly the message
886	            if self.status.is_congested(priority) {
887	                return Ok(false);
888	            }
889	            (
890	                self.status.waits.wait_before_drop,
891	                Some(self.status.waits.max_wait_before_drop_fragments),
892	            )
893	        } else {
894	            (self.status.waits.wait_before_close, None)
895	        };
896	        let mut deadline = Deadline::new(wait_time, max_wait_time);
897	        // Lock the channel. We are the only one that will be writing on it.
898	        let mut queue = zlock!(self.stage_in[idx]);
899	        // Check again for congestion in case it happens when blocking on the mutex.
900	        if msg.is_droppable() && self.status.is_congested(priority) {
901	            return Ok(false);
902	        }
903	        let mut sent = queue.push_network_message(msg, priority, &mut deadline)?;
904	        // If the message cannot be sent, mark the pipeline as congested.
905	        if !sent {
906	            self.status.set_congested(priority, true);
907	            // During the time between deadline wakeup and setting the congested flag,
908	            // all batches could have been refilled (especially if there is a single one),
909	            // so try again with the same already expired deadline.
910	            sent = queue.push_network_message(msg, priority, &mut deadline)?;
911	            // If the message is sent in the end, reset the status.
912	            // Setting the status to `true` is only done with the stage_in mutex acquired,
913	            // so it is not possible that further messages see the congestion flag set
914	            // after this point.
915	            if sent {
916	                self.status.set_congested(priority, false);
917	            }
918	            // There is one edge case that is fortunately supported: if the message that
919	            // has been pushed again is fragmented, we might have some batches actually
920	            // refilled, but still end with dropping the message, not resetting the
921	            // congested flag in that case. However, if some batches were available,
922	            // that means that they would have still been pushed, so we can expect them to
923	            // be refilled, and they will eventually unset the congested flag.
924	        }
925	        Ok(sent)
926	    }
927	
928	    #[inline]
929	    pub(crate) fn push_transport_message(&self, msg: TransportMessage, priority: Priority) -> bool {
930	        // If the queue is not QoS, it means that we only have one priority with index 0.
931	        let priority = if self.stage_in.len() > 1 {
932	            priority as usize
933	        } else {
934	            0
935	        };
936	        // Lock the channel. We are the only one that will be writing on it.
937	        let mut queue = zlock!(self.stage_in[priority]);
938	        queue.push_transport_message(msg)
939	    }
940	
941	    pub(crate) fn disable(&self) {
942	        self.status.set_disabled(true);
943	
944	        // Acquire all the locks, in_guard first, out_guard later
945	        // Use the same locking order as in drain to avoid deadlocks
946	        let mut in_guards: Vec<MutexGuard<'_, StageIn>> =
947	            self.stage_in.iter().map(|x| zlock!(x)).collect();
948	
949	        // Unblock waiting pullers
950	        for ig in in_guards.iter_mut() {
951	            ig.s_out.notify(BatchSize::MAX);
952	        }
953	    }
954	}
