963	pub(crate) trait PipelineConsumer {
964	    #[allow(private_interfaces)]
965	    fn status(&self) -> &TransmissionPipelineStatus;
966	    fn stage_pull(&mut self) -> Result<(BoxedWBatch, Priority), Option<MicroSeconds>>;
967	    fn n_out_r(&self) -> &Waiter;
968	    async fn pull(&mut self) -> Option<(BoxedWBatch, Priority)> {
969	        while !self.status().is_disabled() {
970	            let backoff = match self.stage_pull() {
971	                Ok(res) => return Some(res),
972	                Err(b) => b,
973	            };
974	            // In case of writing many small messages, `recv_async()` will most likely return immediately.
975	            // While trying to pull from the queue, the stage_in `lock()` will most likely taken, leading to
976	            // a spinning behaviour while attempting to take the lock. Yield the current task to avoid
977	            // spinning the current task indefinitely.
978	            tokio::task::yield_now().await;
979	
980	            // Wait for the backoff to expire or for a new message
981	            let backoff_wait = match backoff {
982	                Some(b) => {
983	                    tokio::time::timeout(
984	                        Duration::from_micros(b as u64),
985	                        self.n_out_r().wait_async(),
986	                    )
987	                    .await
988	                }
989	                None => Ok(self.n_out_r().wait_async().await),
990	            };
991	            match backoff_wait {
992	                Ok(Ok(())) => {
993	                    // We have received a notification from the channel that some bytes are available, retry to pull.
994	                }
995	                Ok(Err(_channel_error)) => {
996	                    // The channel is closed, we can't be notified anymore. Break the loop and return None.
997	                    break;
998	                }
999	                Err(_timeout) => {
1000	                    // The backoff timeout expired. Be aware that tokio timeout may not sleep for short duration since
1001	                    // it has time resolution of 1ms: https://docs.rs/tokio/latest/tokio/time/fn.sleep.html
1002	                }
1003	            }
1004	        }
1005	        None
1006	    }
1007	    fn refill(&mut self, batch: BoxedWBatch, priority: Priority);
1008	    fn drain(&mut self) -> Vec<(BoxedWBatch, Priority)>;
1009	}
1010	
1011	impl PipelineConsumer for TransmissionPipelineConsumer {
1012	    #[allow(private_interfaces)]
1013	    fn status(&self) -> &TransmissionPipelineStatus {
1014	        &self.status
1015	    }
1016	
1017	    fn stage_pull(&mut self) -> Result<(BoxedWBatch, Priority), Option<MicroSeconds>> {
1018	        while let Some(prio) = self.status.get_pending() {
1019	            let queue = &mut self.stage_out[prio as usize];
1020	            match queue.try_pull() {
1021	                Pull::Some(batch) => return Ok((batch, prio)),
1022	                Pull::Backoff(deadline) => return Err(Some(deadline)),
1023	                Pull::None => {}
1024	            }
1025	        }
1026	        Err(None)
1027	    }
1028	
1029	    fn n_out_r(&self) -> &Waiter {
1030	        self.n_out_r.as_ref().unwrap()
1031	    }
1032	
1033	    fn refill(&mut self, batch: BoxedWBatch, priority: Priority) {
1034	        if !batch.is_ephemeral() {
1035	            self.stage_out[priority as usize].refill(batch);
1036	            self.status.set_congested(priority, false);
1037	        }
1038	    }
1039	
1040	    fn drain(&mut self) -> Vec<(BoxedWBatch, Priority)> {
1041	        // Drain the remaining batches
1042	        let mut batches = vec![];
1043	
1044	        // Acquire all the locks, in_guard first, out_guard later
1045	        // Use the same locking order as in disable to avoid deadlocks
1046	        let locks = self
1047	            .stage_out
1048	            .iter()
1049	            .map(|x| x.s_in.current.clone())
1050	            .collect::<Vec<_>>();
1051	        let mut currents: Vec<_> = locks.iter().map(|x| zlock!(x)).collect::<Vec<_>>();
1052	
1053	        for (prio, s_out) in self.stage_out.iter_mut().enumerate() {
1054	            let mut bs = s_out.drain(&mut currents[prio]);
1055	            for b in bs.drain(..) {
1056	                batches.push((b, Priority::try_from(prio as u8).unwrap()));
1057	            }
1058	        }
1059	
1060	        batches
1061	    }
1062	}
